    fn settings_repair() {
        assert!(AppSettings::from_json_str("{ not json").is_err());
        assert!(AppSettings::from_json_str("[]").is_err());

        let repaired = AppSettings::from_json_str(
            r#"{
                "log_level": "DEBUG",
                "update_source": "bogus",
                "scanner_OverviewIssues": false,
                "scanner_Errors": "yes",
                "scanner_WrongFormat": false,
