//! Typed settings model for reference-compatible CMT settings data.

use serde_json::{Map, Value, json};

const LOG_LEVEL_KEY: &str = "log_level";
const UPDATE_SOURCE_KEY: &str = "update_source";
const SCANNER_OVERVIEW_ISSUES_KEY: &str = "scanner_OverviewIssues";
const SCANNER_ERRORS_KEY: &str = "scanner_Errors";
const SCANNER_WRONG_FORMAT_KEY: &str = "scanner_WrongFormat";
const SCANNER_LOOSE_PREVIS_KEY: &str = "scanner_LoosePrevis";
const SCANNER_JUNK_FILES_KEY: &str = "scanner_JunkFiles";
const SCANNER_PROBLEM_OVERRIDES_KEY: &str = "scanner_ProblemOverrides";
const SCANNER_RACE_SUBGRAPHS_KEY: &str = "scanner_RaceSubgraphs";
const DOWNGRADER_KEEP_BACKUPS_KEY: &str = "downgrader_keep_backups";
const DOWNGRADER_DELETE_DELTAS_KEY: &str = "downgrader_delete_deltas";

const KNOWN_KEYS: [&str; 11] = [
    LOG_LEVEL_KEY,
    UPDATE_SOURCE_KEY,
    SCANNER_OVERVIEW_ISSUES_KEY,
    SCANNER_ERRORS_KEY,
    SCANNER_WRONG_FORMAT_KEY,
    SCANNER_LOOSE_PREVIS_KEY,
    SCANNER_JUNK_FILES_KEY,
    SCANNER_PROBLEM_OVERRIDES_KEY,
    SCANNER_RACE_SUBGRAPHS_KEY,
    DOWNGRADER_KEEP_BACKUPS_KEY,
    DOWNGRADER_DELETE_DELTAS_KEY,
];

/// Top-level application settings persisted in the reference `settings.json`.
///
/// This aggregate keeps domain settings typed while later platform code owns
/// filesystem paths and save/load side effects.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AppSettings {
    /// Minimum log severity persisted with the `log_level` JSON key.
    pub log_level: LogLevel,
    /// Update channel persisted with the `update_source` JSON key.
    pub update_source: UpdateSource,
    /// Scanner toggles persisted as reference-compatible `scanner_*` keys.
    pub scanner: ScannerSettings,
    /// Downgrader toggles persisted as reference-compatible `downgrader_*` keys.
    pub downgrader: DowngraderSettings,
}

impl Default for AppSettings {
    fn default() -> Self {
        Self {
            log_level: LogLevel::Info,
            update_source: UpdateSource::Nexus,
            scanner: ScannerSettings::default(),
            downgrader: DowngraderSettings::default(),
        }
    }
}

impl AppSettings {
    /// Parses and repairs a syntactically valid JSON settings object.
    ///
    /// Malformed JSON and non-object roots are rejected so the platform store can
    /// perform the reference-compatible defaults-only reset required by D-09 and
    /// D-11. Valid objects preserve each valid known key independently and report
    /// diagnostics for keys that need default repair or removal.
    pub fn from_json_str(source: &str) -> Result<SettingsRepairResult, SettingsParseError> {
        let value: Value =
            serde_json::from_str(source).map_err(SettingsParseError::MalformedJson)?;
        let object = value.as_object().ok_or(SettingsParseError::NonObjectRoot)?;
        Ok(Self::apply_json_object(object))
    }

    /// Applies reference-compatible per-key repair semantics to a JSON object.
    ///
    /// Unknown keys are ignored in memory and therefore omitted when the returned
    /// settings are serialized with [`AppSettings::to_json_value`].
    pub fn apply_json_object(object: &Map<String, Value>) -> SettingsRepairResult {
        let mut settings = Self::default();
        let mut diagnostics = Vec::new();

        for key in KNOWN_KEYS {
            if !object.contains_key(key) {
                diagnostics.push(RepairDiagnostic::MissingKey {
                    key: key.to_owned(),
                });
            }
        }

        for (key, value) in object {
            match key.as_str() {
                LOG_LEVEL_KEY => match value.as_str().and_then(LogLevel::from_wire_value) {
                    Some(log_level) => settings.log_level = log_level,
                    None if value.is_string() => {
                        diagnostics.push(RepairDiagnostic::InvalidValue { key: key.clone() })
                    }
                    None => diagnostics.push(RepairDiagnostic::InvalidType { key: key.clone() }),
                },
                UPDATE_SOURCE_KEY => match value.as_str().and_then(UpdateSource::from_wire_value) {
                    Some(update_source) => settings.update_source = update_source,
                    None if value.is_string() => {
                        diagnostics.push(RepairDiagnostic::InvalidValue { key: key.clone() })
                    }
                    None => diagnostics.push(RepairDiagnostic::InvalidType { key: key.clone() }),
                },
                SCANNER_OVERVIEW_ISSUES_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.overview_issues,
                    &mut diagnostics,
                ),
                SCANNER_ERRORS_KEY => {
                    apply_bool(value, key, &mut settings.scanner.errors, &mut diagnostics)
                }
                SCANNER_WRONG_FORMAT_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.wrong_format,
                    &mut diagnostics,
                ),
                SCANNER_LOOSE_PREVIS_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.loose_previs,
                    &mut diagnostics,
                ),
                SCANNER_JUNK_FILES_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.junk_files,
                    &mut diagnostics,
                ),
                SCANNER_PROBLEM_OVERRIDES_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.problem_overrides,
                    &mut diagnostics,
                ),
                SCANNER_RACE_SUBGRAPHS_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.scanner.race_subgraphs,
                    &mut diagnostics,
                ),
                DOWNGRADER_KEEP_BACKUPS_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.downgrader.keep_backups,
                    &mut diagnostics,
                ),
                DOWNGRADER_DELETE_DELTAS_KEY => apply_bool(
                    value,
                    key,
                    &mut settings.downgrader.delete_deltas,
                    &mut diagnostics,
                ),
                _ => diagnostics.push(RepairDiagnostic::UnknownKey { key: key.clone() }),
            }
        }

        SettingsRepairResult {
            settings,
            diagnostics,
        }
    }

    /// Converts settings into the reference-compatible JSON object shape.
    ///
    /// Keys intentionally preserve the mixed-case scanner names used by
    /// `CMT/src/app_settings.py` so later file IO can resave repaired settings
    /// without introducing Rust-style snake_case key drift.
    pub fn to_json_value(&self) -> Value {
        json!({
            "log_level": self.log_level.as_wire_value(),
            "update_source": self.update_source.as_wire_value(),
            "scanner_OverviewIssues": self.scanner.overview_issues,
            "scanner_Errors": self.scanner.errors,
            "scanner_WrongFormat": self.scanner.wrong_format,
            "scanner_LoosePrevis": self.scanner.loose_previs,
            "scanner_JunkFiles": self.scanner.junk_files,
            "scanner_ProblemOverrides": self.scanner.problem_overrides,
            "scanner_RaceSubgraphs": self.scanner.race_subgraphs,
            "downgrader_keep_backups": self.downgrader.keep_backups,
            "downgrader_delete_deltas": self.downgrader.delete_deltas,
        })
    }
}

fn apply_bool(
    value: &Value,
    key: &str,
    target: &mut bool,
    diagnostics: &mut Vec<RepairDiagnostic>,
) {
    if let Some(value) = value.as_bool() {
        *target = value;
    } else {
        diagnostics.push(RepairDiagnostic::InvalidType {
            key: key.to_owned(),
        });
    }
}

/// Parsed settings plus diagnostics describing any quiet repairs made.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SettingsRepairResult {
    /// Typed settings after valid values were applied and invalid values defaulted.
    pub settings: AppSettings,
    /// Diagnostics for test assertions and later logging; values are deliberately omitted.
    pub diagnostics: Vec<RepairDiagnostic>,
}

/// Non-sensitive diagnostic for a single settings repair action.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum RepairDiagnostic {
    /// A known reference key was absent and retained its default value.
    MissingKey { key: String },
    /// A known enum/string key had an unsupported string value.
    InvalidValue { key: String },
    /// A known key had the wrong JSON type.
    InvalidType { key: String },
    /// An unknown key was ignored and will be omitted on resave.
    UnknownKey { key: String },
}

/// Parse errors that require the platform store to reset settings to defaults.
#[derive(Debug)]
pub enum SettingsParseError {
    /// JSON parsing failed before a trustworthy object could be inspected.
    MalformedJson(serde_json::Error),
    /// The parsed JSON root was not an object.
    NonObjectRoot,
}

/// Reference log level values accepted by the persisted settings contract.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum LogLevel {
    /// Extra-verbose log output.
    Debug,
    /// Reference default log level.
    Info,
    /// Warning-and-above log output accepted by the reference settings schema.
    Warning,
    /// Error-only log output.
    Error,
}

impl LogLevel {
    /// Returns the exact string persisted for this log level in `settings.json`.
    pub const fn as_wire_value(self) -> &'static str {
        match self {
            Self::Debug => "DEBUG",
            Self::Info => "INFO",
            Self::Warning => "WARNING",
            Self::Error => "ERROR",
        }
    }

    /// Converts a persisted log-level string into the typed value when supported.
    pub fn from_wire_value(value: &str) -> Option<Self> {
        match value {
            "DEBUG" => Some(Self::Debug),
            "INFO" => Some(Self::Info),
            "WARNING" => Some(Self::Warning),
            "ERROR" => Some(Self::Error),
            _ => None,
        }
    }
}

/// Update channel persisted for later update-check behavior.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum UpdateSource {
    /// Check both GitHub and Nexus Mods.
    Both,
    /// Check GitHub only.
    Github,
    /// Check Nexus Mods only.
    Nexus,
    /// Do not check for updates.
    None,
}

impl UpdateSource {
    /// Returns the exact string persisted for this update source in `settings.json`.
    pub const fn as_wire_value(self) -> &'static str {
        match self {
            Self::Both => "both",
            Self::Github => "github",
            Self::Nexus => "nexus",
            Self::None => "none",
        }
    }

    /// Converts a persisted update-source string into the typed value when supported.
    pub fn from_wire_value(value: &str) -> Option<Self> {
        match value {
            "both" => Some(Self::Both),
            "github" => Some(Self::Github),
            "nexus" => Some(Self::Nexus),
            "none" => Some(Self::None),
            _ => None,
        }
    }
}

/// Scanner category toggles persisted by the Settings model.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ScannerSettings {
    /// Enables overview issue checks.
    pub overview_issues: bool,
    /// Enables generic error checks.
    pub errors: bool,
    /// Enables wrong file format checks.
    pub wrong_format: bool,
    /// Enables loose previs checks.
    pub loose_previs: bool,
    /// Enables junk file checks.
    pub junk_files: bool,
    /// Enables problematic override checks.
    pub problem_overrides: bool,
    /// Enables race subgraph checks.
    pub race_subgraphs: bool,
}

impl Default for ScannerSettings {
    fn default() -> Self {
        Self {
            overview_issues: true,
            errors: true,
            wrong_format: true,
            loose_previs: true,
            junk_files: true,
            problem_overrides: true,
            race_subgraphs: true,
        }
    }
}

/// Downgrader workflow preferences persisted by the Settings model.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DowngraderSettings {
    /// Keeps backups when later downgrader operations modify files.
    pub keep_backups: bool,
    /// Deletes delta files after later downgrader operations use them.
    pub delete_deltas: bool,
}

impl Default for DowngraderSettings {
    fn default() -> Self {
        Self {
            keep_backups: true,
            delete_deltas: true,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    const REFERENCE_KEYS: [&str; 11] = [
        "log_level",
        "update_source",
        "scanner_OverviewIssues",
        "scanner_Errors",
        "scanner_WrongFormat",
        "scanner_LoosePrevis",
        "scanner_JunkFiles",
        "scanner_ProblemOverrides",
        "scanner_RaceSubgraphs",
        "downgrader_keep_backups",
        "downgrader_delete_deltas",
    ];

    #[test]
    fn settings_missing_file_defaults() {
        let settings = AppSettings::default();

        assert_eq!(settings.log_level, LogLevel::Info);
        assert_eq!(settings.update_source, UpdateSource::Nexus);
        assert!(settings.downgrader.keep_backups);
        assert!(settings.downgrader.delete_deltas);
    }

    #[test]
    fn settings_persist_reference_keys() {
        let json = AppSettings::default().to_json_value();
        let object = json
            .as_object()
            .expect("settings should serialize as object");

        let mut keys: Vec<&str> = object.keys().map(String::as_str).collect();
        keys.sort_unstable();
        let mut expected_keys = REFERENCE_KEYS.to_vec();
        expected_keys.sort_unstable();
        assert_eq!(keys, expected_keys);

        assert_eq!(json["log_level"], "INFO");
        assert_eq!(LogLevel::Debug.as_wire_value(), "DEBUG");
        assert_eq!(LogLevel::Info.as_wire_value(), "INFO");
        assert_eq!(LogLevel::Warning.as_wire_value(), "WARNING");
        assert_eq!(LogLevel::Error.as_wire_value(), "ERROR");
        assert_eq!(json["update_source"], "nexus");
        assert!(!object.contains_key("scanner_overview_issues"));
        assert!(!object.contains_key("scanner_wrong_format"));
    }

    #[test]
    fn scanner_settings_defaults_enabled() {
        let scanner = ScannerSettings::default();

        assert!(scanner.overview_issues);
        assert!(scanner.errors);
        assert!(scanner.wrong_format);
        assert!(scanner.loose_previs);
        assert!(scanner.junk_files);
        assert!(scanner.problem_overrides);
        assert!(scanner.race_subgraphs);
    }

    #[test]
    fn settings_repair() {
        assert!(AppSettings::from_json_str("{ not json").is_err());
        assert!(AppSettings::from_json_str("[]").is_err());

        let repaired = AppSettings::from_json_str(
            r#"{
                "log_level": "DEBUG",
                "update_source": "bogus",
                "scanner_OverviewIssues": false,
                "scanner_Errors": "yes",
                "scanner_WrongFormat": false,
                "scanner_LoosePrevis": false,
                "scanner_JunkFiles": false,
                "scanner_ProblemOverrides": false,
                "scanner_RaceSubgraphs": false,
                "downgrader_keep_backups": false,
                "unknown_setting": true
            }"#,
        )
        .expect("syntactically valid JSON object should repair per key");

        assert_eq!(repaired.settings.log_level, LogLevel::Debug);
        assert_eq!(repaired.settings.update_source, UpdateSource::Nexus);
        assert!(!repaired.settings.scanner.overview_issues);
        assert!(repaired.settings.scanner.errors);
        assert!(!repaired.settings.scanner.wrong_format);
        assert!(!repaired.settings.scanner.loose_previs);
        assert!(!repaired.settings.scanner.junk_files);
        assert!(!repaired.settings.scanner.problem_overrides);
        assert!(!repaired.settings.scanner.race_subgraphs);
        assert!(!repaired.settings.downgrader.keep_backups);
        assert!(repaired.settings.downgrader.delete_deltas);

        assert!(repaired.diagnostics.iter().any(|diagnostic| {
            matches!(diagnostic, RepairDiagnostic::InvalidValue { key } if key == "update_source")
        }));
        assert!(repaired.diagnostics.iter().any(|diagnostic| {
            matches!(diagnostic, RepairDiagnostic::InvalidType { key } if key == "scanner_Errors")
        }));
        assert!(repaired.diagnostics.iter().any(|diagnostic| {
            matches!(diagnostic, RepairDiagnostic::MissingKey { key } if key == "downgrader_delete_deltas")
        }));
        assert!(repaired.diagnostics.iter().any(|diagnostic| {
            matches!(diagnostic, RepairDiagnostic::UnknownKey { key } if key == "unknown_setting")
        }));

        let repaired_json = repaired.settings.to_json_value();
        let repaired_object = repaired_json
            .as_object()
            .expect("repaired settings should serialize as object");
        assert!(!repaired_object.contains_key("unknown_setting"));

        let warning = AppSettings::from_json_str(r#"{"log_level":"WARNING"}"#)
            .expect("reference-valid WARNING log_level should load");
        assert_eq!(warning.settings.log_level, LogLevel::Warning);
    }
}

//! Filesystem-backed settings store for reference-compatible CMT settings IO.

use std::{
    fs, io,
    path::{Path, PathBuf},
};

use crate::domain::settings::{AppSettings, RepairDiagnostic, SettingsParseError, UpdateSource};

const SETTINGS_FILE_NAME: &str = "settings.json";
const DOWNLOAD_SOURCE_FILE_NAME: &str = "download-source.txt";

/// Resolves auxiliary settings assets such as `download-source.txt`.
///
/// The abstraction keeps packaged asset lookup separate from settings file IO so
/// tests can inject paths and later packaging can mirror CMT's asset directory
/// behavior without coupling assets to `settings.json` placement.
pub trait AssetResolver {
    /// Reads the configured download source text if the asset is available.
    ///
    /// Returning `Ok(None)` represents a missing asset and causes the settings
    /// store to use the reference-compatible Nexus fallback.
    fn read_download_source(&self) -> io::Result<Option<String>>;
}

/// Filesystem asset resolver rooted at a specific `download-source.txt` path.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct FileAssetResolver {
    download_source_path: PathBuf,
}

impl FileAssetResolver {
    /// Creates a resolver for an explicit `download-source.txt` path.
    pub fn new(download_source_path: PathBuf) -> Self {
        Self {
            download_source_path,
        }
    }

    /// Creates the production resolver for `assets/download-source.txt`.
    ///
    /// This mirrors `CMT/src/utils.py::get_asset_path` for non-PyInstaller runs:
    /// assets are resolved under the current directory's `assets` folder, not
    /// beside `settings.json`.
    pub fn production() -> Self {
        Self::new(PathBuf::from("assets").join(DOWNLOAD_SOURCE_FILE_NAME))
    }
}

impl AssetResolver for FileAssetResolver {
    fn read_download_source(&self) -> io::Result<Option<String>> {
        match fs::read_to_string(&self.download_source_path) {
            Ok(source) => Ok(Some(source.trim().to_owned())),
            Err(error) if error.kind() == io::ErrorKind::NotFound => Ok(None),
            Err(error) => Err(error),
        }
    }
}

/// Test and controller helper that returns a fixed asset value.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct StaticAssetResolver {
    download_source: Option<String>,
}

impl StaticAssetResolver {
    /// Creates a resolver that returns the provided download source text.
    pub fn new(download_source: Option<&str>) -> Self {
        Self {
            download_source: download_source.map(str::to_owned),
        }
    }
}

impl AssetResolver for StaticAssetResolver {
    fn read_download_source(&self) -> io::Result<Option<String>> {
        Ok(self.download_source.clone())
    }
}

/// Settings and asset paths used by [`SettingsStore`].
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SettingsPaths<R = FileAssetResolver> {
    settings_path: PathBuf,
    asset_resolver: R,
}

impl SettingsPaths<FileAssetResolver> {
    /// Creates production paths using current-directory `settings.json`.
    pub fn production() -> Self {
        Self {
            settings_path: PathBuf::from(SETTINGS_FILE_NAME),
            asset_resolver: FileAssetResolver::production(),
        }
    }
}

impl<R: AssetResolver> SettingsPaths<R> {
    /// Creates injectable paths for tests or controller-owned settings files.
    pub fn injected(settings_path: PathBuf, asset_resolver: R) -> Self {
        Self {
            settings_path,
            asset_resolver,
        }
    }

    /// Returns the settings JSON path used by the store.
    pub fn settings_path(&self) -> PathBuf {
        self.settings_path.clone()
    }
}

/// Filesystem-backed load/save boundary for [`crate::domain::settings::AppSettings`].
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SettingsStore<R = FileAssetResolver> {
    paths: SettingsPaths<R>,
}

/// Result returned by [`SettingsStore::load`] after any reference-style repair.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct LoadedSettings {
    /// Settings ready for UI/controller use.
    pub settings: AppSettings,
    /// Non-sensitive repair diagnostics collected while loading.
    pub diagnostics: Vec<RepairDiagnostic>,
    /// True when the file was missing, malformed, unreadable, or non-object JSON.
    pub reset_to_defaults: bool,
}

impl SettingsStore<FileAssetResolver> {
    /// Creates a store with production current-directory settings and asset paths.
    pub fn production() -> Self {
        Self::new(SettingsPaths::production())
    }
}

impl<R: AssetResolver> SettingsStore<R> {
    /// Creates a store from explicit settings paths.
    pub fn new(paths: SettingsPaths<R>) -> Self {
        Self { paths }
    }

    /// Creates a store from a settings path and asset resolver.
    pub fn with_asset_resolver(settings_path: PathBuf, asset_resolver: R) -> Self {
        Self::new(SettingsPaths::injected(settings_path, asset_resolver))
    }

    /// Returns the settings file path without touching the filesystem.
    pub fn settings_path(&self) -> &Path {
        &self.paths.settings_path
    }

    /// Resolves the default update source through `download-source.txt`.
    ///
    /// Missing, unreadable, or invalid content falls back to Nexus so a damaged
    /// packaged asset never prevents startup.
    pub fn default_update_source(&self) -> UpdateSource {
        self.paths
            .asset_resolver
            .read_download_source()
            .ok()
            .flatten()
            .as_deref()
            .and_then(UpdateSource::from_wire_value)
            .unwrap_or(UpdateSource::Nexus)
    }

    /// Loads settings, creating or repairing `settings.json` as needed.
    ///
    /// Missing files and malformed/non-object JSON reset to default settings and
    /// are saved immediately, matching the reference app's quiet first-run and
    /// recovery behavior. Syntactically valid objects preserve valid keys, repair
    /// invalid values, remove unknown keys on resave, and return diagnostics for
    /// later logging without surfacing UI errors.
    pub fn load(&self) -> io::Result<LoadedSettings> {
        let defaults = AppSettings {
            update_source: self.default_update_source(),
            ..Default::default()
        };

        let source = match fs::read_to_string(&self.paths.settings_path) {
            Ok(source) => source,
            Err(error) if error.kind() == io::ErrorKind::NotFound => {
                self.save(&defaults)?;
                return Ok(LoadedSettings {
                    settings: defaults,
                    diagnostics: Vec::new(),
                    reset_to_defaults: true,
                });
            }
            Err(_) => {
                self.save(&defaults)?;
                return Ok(LoadedSettings {
                    settings: defaults,
                    diagnostics: Vec::new(),
                    reset_to_defaults: true,
                });
            }
        };

        let repaired = match AppSettings::from_json_str(&source) {
            Ok(repaired) => repaired,
            Err(SettingsParseError::MalformedJson(_)) | Err(SettingsParseError::NonObjectRoot) => {
                self.save(&defaults)?;
                return Ok(LoadedSettings {
                    settings: defaults,
                    diagnostics: Vec::new(),
                    reset_to_defaults: true,
                });
            }
        };

        if !repaired.diagnostics.is_empty() {
            self.save(&repaired.settings)?;
        }

        Ok(LoadedSettings {
            settings: repaired.settings,
            diagnostics: repaired.diagnostics,
            reset_to_defaults: false,
        })
    }

    /// Saves settings JSON and returns filesystem errors to the caller.
    ///
    /// The serialized object is produced by the domain model, so unknown keys are
    /// never persisted and later UI/controller code can revert state if this file
    /// write fails.
    pub fn save(&self, settings: &AppSettings) -> io::Result<()> {
        let mut json =
            serde_json::to_string_pretty(&settings.to_json_value()).map_err(io::Error::other)?;
        json.push('\n');
        fs::write(&self.paths.settings_path, json)
    }
}

#[cfg(test)]
mod tests {
    use std::{
        fs,
        path::PathBuf,
        time::{SystemTime, UNIX_EPOCH},
    };

    use crate::domain::settings::{AppSettings, LogLevel, UpdateSource};

    use super::*;

    #[test]
    fn settings_store_uses_current_directory_settings_json_by_default() {
        let paths = SettingsPaths::production();

        assert_eq!(paths.settings_path(), PathBuf::from("settings.json"));
    }

    #[test]
    fn injected_paths_and_asset_resolver_drive_update_source_defaults() {
        let temp_root = std::env::temp_dir().join("cmt-rs-settings-store-red");
        let settings_path = temp_root.join("isolated-settings.json");
        let asset_path = temp_root.join("download-source.txt");
        let paths =
            SettingsPaths::injected(settings_path.clone(), FileAssetResolver::new(asset_path));
        let store = SettingsStore::new(paths);

        assert_eq!(store.settings_path(), settings_path.as_path());
        assert_eq!(store.default_update_source(), UpdateSource::Nexus);
    }

    #[test]
    fn asset_resolver_rejects_invalid_download_source_with_nexus_fallback() {
        let resolver = StaticAssetResolver::new(Some("invalid-source"));
        let store = SettingsStore::with_asset_resolver(PathBuf::from("settings.json"), resolver);

        assert_eq!(store.default_update_source(), UpdateSource::Nexus);
    }

    #[test]
    fn file_asset_resolver_reads_valid_download_source_file_values() {
        for (wire_value, expected_source) in [
            ("github", UpdateSource::Github),
            ("nexus", UpdateSource::Nexus),
        ] {
            let (root, settings_path) = isolated_settings_path(wire_value);
            let asset_path = root.join("download-source.txt");
            fs::write(&asset_path, format!("\n{wire_value}\n"))
                .expect("test fixture should write download-source.txt");
            let store = SettingsStore::with_asset_resolver(
                settings_path,
                FileAssetResolver::new(asset_path),
            );

            assert_eq!(store.default_update_source(), expected_source);
        }
    }

    #[test]
    fn settings_missing_file_defaults() {
        let (_root, settings_path) = isolated_settings_path("missing-defaults");
        let store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("github")),
        );

        let loaded = store
            .load()
            .expect("missing settings should create defaults");

        assert_eq!(loaded.settings.update_source, UpdateSource::Github);
        assert!(settings_path.is_file());
        let persisted = fs::read_to_string(settings_path).expect("defaults should be persisted");
        assert_eq!(persisted_json(&persisted)["update_source"], "github");
    }

    #[test]
    fn settings_repair_malformed_json_resets_to_defaults() {
        let (_root, settings_path) = isolated_settings_path("malformed-reset");
        fs::write(&settings_path, "{ not json").expect("test fixture should write malformed JSON");
        let store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("both")),
        );

        let loaded = store
            .load()
            .expect("malformed JSON should reset to defaults");

        assert!(loaded.reset_to_defaults);
        assert_eq!(loaded.settings.update_source, UpdateSource::Both);
        let persisted =
            fs::read_to_string(settings_path).expect("defaults should replace malformed JSON");
        assert_eq!(persisted_json(&persisted)["update_source"], "both");
    }

    #[test]
    fn settings_repair_partial_json_preserves_valid_fields_and_removes_unknown_keys() {
        let (_root, settings_path) = isolated_settings_path("partial-repair");
        fs::write(
            &settings_path,
            r#"{
                "log_level": "WARNING",
                "update_source": "github",
                "scanner_OverviewIssues": false,
                "scanner_Errors": true,
                "unknown_setting": true
            }"#,
        )
        .expect("test fixture should write partial JSON");
        let store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("nexus")),
        );

        let loaded = store.load().expect("partial JSON should repair and resave");

        assert_eq!(loaded.settings.log_level, LogLevel::Warning);
        assert_eq!(loaded.settings.update_source, UpdateSource::Github);
        assert!(!loaded.settings.scanner.overview_issues);
        let persisted =
            fs::read_to_string(settings_path).expect("repaired settings should be persisted");
        let persisted_json = persisted_json(&persisted);
        assert_eq!(persisted_json["log_level"], "WARNING");
        assert_eq!(persisted_json["update_source"], "github");
        assert!(persisted_json.get("unknown_setting").is_none());
    }

    #[test]
    fn settings_persist_reference_keys() {
        let (_root, settings_path) = isolated_settings_path("persist-reference-keys");
        let store = SettingsStore::with_asset_resolver(
            settings_path.clone(),
            StaticAssetResolver::new(Some("nexus")),
        );

        store
            .save(&AppSettings::default())
            .expect("default settings should save");

        let persisted = fs::read_to_string(settings_path).expect("settings should be readable");
        let object = persisted_json(&persisted);
        let mut keys: Vec<&str> = object.keys().map(String::as_str).collect();
        keys.sort_unstable();
        assert_eq!(
            keys,
            vec![
                "downgrader_delete_deltas",
                "downgrader_keep_backups",
                "log_level",
                "scanner_Errors",
                "scanner_JunkFiles",
                "scanner_LoosePrevis",
                "scanner_OverviewIssues",
                "scanner_ProblemOverrides",
                "scanner_RaceSubgraphs",
                "scanner_WrongFormat",
                "update_source",
            ]
        );
        assert_eq!(LogLevel::Debug.as_wire_value(), "DEBUG");
        assert_eq!(LogLevel::Info.as_wire_value(), "INFO");
        assert_eq!(LogLevel::Warning.as_wire_value(), "WARNING");
        assert_eq!(LogLevel::Error.as_wire_value(), "ERROR");
    }

    #[test]
    fn settings_save_failure_is_returned() {
        let (_root, settings_path) = isolated_settings_path("save-failure");
        fs::create_dir_all(&settings_path)
            .expect("directory at settings path should block file write");
        let store =
            SettingsStore::with_asset_resolver(settings_path, StaticAssetResolver::new(None));

        let error = store
            .save(&AppSettings::default())
            .expect_err("save should return an observable filesystem error");

        assert_ne!(error.kind(), io::ErrorKind::NotFound);
    }

    fn isolated_settings_path(case_name: &str) -> (PathBuf, PathBuf) {
        let unique = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .expect("system time should be after Unix epoch")
            .as_nanos();
        let root = std::env::temp_dir().join(format!("cmt-rs-{case_name}-{unique}"));
        fs::create_dir_all(&root).expect("test temp directory should be created");
        let settings_path = root.join("settings.json");
        (root, settings_path)
    }

    fn persisted_json(source: &str) -> serde_json::Map<String, serde_json::Value> {
        serde_json::from_str::<serde_json::Value>(source)
            .expect("persisted settings should be JSON")
            .as_object()
            .expect("persisted settings should be a JSON object")
            .clone()
    }
}

use std::io;

use crate::{
    domain::settings::{AppSettings, LogLevel, UpdateSource},
    platform::settings_store::{AssetResolver, SettingsStore},
};

/// Coordinates Settings-tab UI selections with persisted application settings.
///
/// The controller keeps the last successfully persisted settings snapshot so a
/// failed immediate-save radio change can return the previous value for Slint to
/// display. It does not reconfigure runtime logging; log-level selections only
/// update the persisted `settings.json` value in this phase.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SettingsController<R> {
    store: SettingsStore<R>,
    last_persisted: AppSettings,
}

impl<R: AssetResolver> SettingsController<R> {
    /// Loads settings through the provided store and initializes UI-facing state.
    ///
    /// Any repairs performed by the settings store are reflected in the initial
    /// snapshot. Reference-valid persisted values, including `WARNING`, are
    /// preserved and mapped onto their displayed radio choices.
    pub fn load(store: SettingsStore<R>) -> io::Result<Self> {
        let loaded = store.load()?;

        Ok(Self::from_settings(store, loaded.settings))
    }

    /// Creates a controller around a known settings snapshot without loading from disk.
    ///
    /// This is used as a startup fallback when the production store cannot load or
    /// create `settings.json`; subsequent selections still attempt to save through
    /// the same store and revert to this snapshot if persistence continues to fail.
    pub fn from_settings(store: SettingsStore<R>, settings: AppSettings) -> Self {
        Self {
            store,
            last_persisted: settings,
        }
    }

    /// Returns the update-source value Slint should display for the current snapshot.
    pub fn visible_update_source(&self) -> &'static str {
        self.last_persisted.update_source.as_wire_value()
    }

    /// Returns the lowercase log-level value Slint should display for the current snapshot.
    pub fn visible_log_level(&self) -> &'static str {
        log_level_to_ui_value(self.last_persisted.log_level)
    }

    /// Persists an Update Channel radio selection and returns the UI value to show.
    ///
    /// Unknown callback strings are treated as tampered input and the previous
    /// persisted UI value is returned without saving. If saving a known value
    /// fails, the previous snapshot is preserved and returned for UI reversion.
    pub fn select_update_source(&mut self, selected: &str) -> &'static str {
        let Some(update_source) = UpdateSource::from_wire_value(selected) else {
            tracing::error!(
                selected,
                "Settings : Invalid update source selection; reverting"
            );
            return self.visible_update_source();
        };

        let mut candidate = self.last_persisted.clone();
        candidate.update_source = update_source;
        self.save_candidate(candidate, AppSettings::update_source_ui_value)
    }

    /// Persists a Log Level radio selection and returns the lowercase UI value to show.
    ///
    /// Slint emits lowercase values, while the domain model persists uppercase
    /// wire values. Unsupported callback strings are
    /// repaired to `INFO` before saving so tampered UI input cannot persist an
    /// unrepresented radio state.
    pub fn select_log_level(&mut self, selected: &str) -> &'static str {
        let log_level = ui_value_to_log_level(selected).unwrap_or_else(|| {
            tracing::error!(
                selected,
                "Settings : Invalid log level selection; repairing to INFO"
            );
            LogLevel::Info
        });

        let mut candidate = self.last_persisted.clone();
        candidate.log_level = log_level;
        self.save_candidate(candidate, AppSettings::log_level_ui_value)
    }

    fn save_candidate(
        &mut self,
        candidate: AppSettings,
        visible_value: impl FnOnce(&AppSettings) -> &'static str,
    ) -> &'static str {
        let previous_update_source = self.visible_update_source();
        let previous_log_level = self.visible_log_level();

        match self.store.save(&candidate) {
            Ok(()) => {
                self.last_persisted = candidate;
                visible_value(&self.last_persisted)
            }
            Err(error) => {
                tracing::error!(
                    path = %self.store.settings_path().display(),
                    %error,
                    "Settings : Failed to save settings; reverting UI selection"
                );
                // Preserve the pre-save snapshot: callers reset the Slint property to this value.
                match visible_value(&candidate) {
                    "debug" | "info" | "warning" | "error" => previous_log_level,
                    _ => previous_update_source,
                }
            }
        }
    }
}

impl AppSettings {
    fn update_source_ui_value(&self) -> &'static str {
        self.update_source.as_wire_value()
    }

    fn log_level_ui_value(&self) -> &'static str {
        log_level_to_ui_value(self.log_level)
    }
}

fn ui_value_to_log_level(value: &str) -> Option<LogLevel> {
    match value {
        "debug" => Some(LogLevel::Debug),
        "info" => Some(LogLevel::Info),
        "warning" => Some(LogLevel::Warning),
        "error" => Some(LogLevel::Error),
        _ => None,
    }
}

fn log_level_to_ui_value(log_level: LogLevel) -> &'static str {
    match log_level {
        LogLevel::Debug => "debug",
        LogLevel::Info => "info",
        LogLevel::Warning => "warning",
        LogLevel::Error => "error",
    }
}

